mapper.select:
select
    tg.id,
    tg.tier_name,
    tg.tier_image_url tierIcon,
    tg.group_date
from tournament_group tg
inner join tournament_group_record tgr on tg.id = tgr.group_id
where tg.event_game_id = #{eventGameId}
and tg.stage_type = #{stageType}
and tg.stage_number = #{stageNumber}
and tgr.participant_id = #{participantId}
and tgr.participant_type = #{participantType}
limit 1
